### 8. Index File Generation

#### `src/build-index-file.ts`

```typescript
import type * as DMMF from '@prisma/dmmf'

function toKebabCase(name: string): string {
  return name.replace(/([A-Z])/g, (m, c, i) => (i === 0 ? c : `-${c}`)).toLowerCase()
}

export function buildIndexFile(
  models: readonly DMMF.Model[],
  enums: readonly DMMF.DatamodelEnum[],
): string {
  const lines: string[] = []

  if (enums.length > 0) {
    lines.push(`export * from './enums'`)
  }

  for (const model of models) {
    lines.push(`export * from './${toKebabCase(model.name)}'`)
  }

  return lines.join('\n') + '\n'
}
```

