### 3. Source Files

#### `src/index.ts` — generator entry point

This is where `generatorHandler` is called. The file is the esbuild entry point, so it both exports and runs the handler when executed directly.

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'
import { generatorHandler } from '@prisma/generator-helper'

import { generate } from './generate'

generatorHandler({
  onManifest() {
    return {
      defaultOutput: './generated/rest-client',
      prettyName: 'Prisma REST Client',
    }
  },

  async onGenerate(options: GeneratorOptions): Promise<void> {
    const outputDir = options.generator.output?.value
    if (!outputDir) {
      throw new Error(
        'An output path is required for the `prisma-generator-rest-client` generator.\n' +
          'Add `output = "./generated/rest-client"` to your generator block.',
      )
    }
    await generate(options.dmmf, outputDir)
  },
})
```

Note: `options.generator.output` is of type `EnvValue | null`. The `.value` field holds the resolved path. If the user sets `output` in their schema, `isCustomOutput` is true and `output.value` is set by the Prisma engine before `onGenerate` is called.

#### `src/generate.ts` — orchestrator

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { buildIndexFile } from './build-index-file'
import { buildModelClient } from './build-model-client'
import { buildModelInterface, buildEnumDeclarations } from './build-model-interface'
import { buildInputTypes } from './build-input-types'

export async function generate(dmmf: DMMF.Document, outputDir: string): Promise<void> {
  await fs.mkdir(outputDir, { recursive: true })

  const { models, enums } = dmmf.datamodel
  const fileMap: Record<string, string> = {}

  for (const model of models) {
    const modelInterface = buildModelInterface(model, enums)
    const inputTypes = buildInputTypes(model)
    const clientClass = buildModelClient(model)
    fileMap[`${toKebabCase(model.name)}.ts`] = [modelInterface, inputTypes, clientClass].join('\n\n')
  }

  fileMap['enums.ts'] = buildEnumDeclarations(enums)
  fileMap['index.ts'] = buildIndexFile(models, enums)

  await Promise.all(
    Object.entries(fileMap).map(async ([filename, content]) => {
      const filepath = path.join(outputDir, filename)
      await fs.rm(filepath, { force: true })
      await fs.writeFile(filepath, content, 'utf-8')
    }),
  )
}

function toKebabCase(name: string): string {
  return name
    .replace(/([A-Z])/g, (m, c, i) => (i === 0 ? c : `-${c}`))
    .toLowerCase()
}
```

Each model becomes its own file (kebab-cased). A separate `enums.ts` holds enum declarations. An `index.ts` re-exports everything.

