### 7. REST Client Class Generation

#### `src/build-model-client.ts`

The generated class is configurable with a base URL and uses the native `fetch` API.

```typescript
import type * as DMMF from '@prisma/dmmf'

export function buildModelClient(model: DMMF.Model): string {
  const n = model.name
  const resource = n.charAt(0).toLowerCase() + n.slice(1) // e.g., User -> user

  return `export class ${n}RestClient {
  constructor(private readonly baseUrl: string) {}

  async findMany(params?: { where?: Partial<${n}>; skip?: number; take?: number }): Promise<${n}[]> {
    const query = buildQuery(params ?? {})
    const res = await fetch(\`\${this.baseUrl}/${resource}\${query}\`)
    if (!res.ok) throw new Error(\`findMany ${n} failed: \${res.status}\`)
    return res.json() as Promise<${n}[]>
  }

  async findUnique(params: { where: ${n}WhereUniqueInput }): Promise<${n} | null> {
    const query = buildQuery(params.where)
    const res = await fetch(\`\${this.baseUrl}/${resource}/findUnique\${query}\`)
    if (!res.ok) {
      if (res.status === 404) return null
      throw new Error(\`findUnique ${n} failed: \${res.status}\`)
    }
    return res.json() as Promise<${n}>
  }

  async create(params: { data: ${n}CreateInput }): Promise<${n}> {
    const res = await fetch(\`\${this.baseUrl}/${resource}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    if (!res.ok) throw new Error(\`create ${n} failed: \${res.status}\`)
    return res.json() as Promise<${n}>
  }

  async update(params: { where: ${n}WhereUniqueInput; data: ${n}UpdateInput }): Promise<${n}> {
    const query = buildQuery(params.where)
    const res = await fetch(\`\${this.baseUrl}/${resource}\${query}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    if (!res.ok) throw new Error(\`update ${n} failed: \${res.status}\`)
    return res.json() as Promise<${n}>
  }

  async delete(params: { where: ${n}WhereUniqueInput }): Promise<${n}> {
    const query = buildQuery(params.where)
    const res = await fetch(\`\${this.baseUrl}/${resource}\${query}\`, { method: 'DELETE' })
    if (!res.ok) throw new Error(\`delete ${n} failed: \${res.status}\`)
    return res.json() as Promise<${n}>
  }
}

function buildQuery(params: Record<string, unknown>): string {
  const entries = Object.entries(params).filter(([, v]) => v !== undefined)
  if (entries.length === 0) return ''
  return '?' + new URLSearchParams(entries.map(([k, v]) => [k, String(v)])).toString()
}`
}
```

**Design decisions:**
- `findUnique` uses a dedicated `/findUnique` URL suffix to distinguish from `findMany`. The actual HTTP routing is server-side — this generator only produces the client.
- `buildQuery` is emitted as a local helper inside each model file. If there are many models, a shared `_utils.ts` could hold it, but co-locating it avoids an extra import.
- `fetch` is used directly without a polyfill. Targets Node 18+ and all browsers natively support it.

