import type * as DMMF from '@prisma/dmmf'

import { mapScalarType } from './map-scalar-type'

/**
 * Generates the TypeScript interface declaration for a model, including only
 * scalar and enum fields. Relation fields are excluded because they are not
 * directly representable in a flat REST response.
 */
export function buildModelInterface(model: DMMF.Model): string {
  const fields = model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')

  const members = fields.map((f) => {
    const tsType = mapScalarType(f)
    const list = f.isList ? '[]' : ''
    const optional = !f.isRequired ? '?' : ''
    return `  ${f.name}${optional}: ${tsType}${list}`
  })

  return `export interface ${model.name} {\n${members.join('\n')}\n}`
}

