import { mkdir, writeFile } from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'
import type { GeneratorOptions } from '@prisma/generator-helper'

import { buildIndexFile } from './build-index-file'
import { buildInputTypes } from './build-input-types'
import { buildModelClient } from './build-model-client'
import { buildModelInterface } from './build-model-interface'

/** Converts a PascalCase model name to a kebab-case file basename. */
function toKebabCase(name: string): string {
  return name
    .replace(/([a-z])([A-Z])/g, '$1-$2')
    .replace(/([A-Z]+)([A-Z][a-z])/g, '$1-$2')
    .toLowerCase()
}

function buildEnumsFile(enums: readonly DMMF.DatamodelEnum[]): string {
  if (enums.length === 0) return '// no enums\n'
  return (
    enums
      .map((e) => {
        const members = e.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
        return `export enum ${e.name} {\n${members}\n}`
      })
      .join('\n\n') + '\n'
  )
}

function buildModelFile(model: DMMF.Model): string {
  return [buildModelInterface(model), '', buildInputTypes(model), '', buildModelClient(model), ''].join('\n')
}

/** Runs the generator: writes one `.ts` file per model plus `enums.ts` and `index.ts`. */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error('@prisma/generator-rest-client: no output directory configured')
  }

  const { datamodel } = options.dmmf

  await mkdir(outputDir, { recursive: true })

  await writeFile(path.join(outputDir, 'enums.ts'), buildEnumsFile(datamodel.enums), 'utf-8')

  const modelFileBasenames: string[] = []
  for (const model of datamodel.models) {
    const basename = toKebabCase(model.name)
    await writeFile(path.join(outputDir, `${basename}.ts`), buildModelFile(model), 'utf-8')
    modelFileBasenames.push(basename)
  }

  await writeFile(path.join(outputDir, 'index.ts'), buildIndexFile(modelFileBasenames), 'utf-8')
}

